#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=5e4+5;
int n,dp[maxn][2],a[maxn],flag[maxn],root;
vector<int> g[maxn];
void dfs(int u,int fa){
	dp[u][0]=0;
	dp[u][1]=a[u];
	for(auto v:g[u]){
		if(v==fa){
			continue;
		}
		dfs(v,u);
		dp[u][1]+=dp[v][0];
		dp[u][0]+=max(dp[v][0],dp[v][1]);
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	for(int i=1; i<n; i++) {
		int a,b;
		cin>>a>>b;
		g[a].emplace_back(b);
		g[b].emplace_back(a);
		flag[b]=1;
	}
	for(int i=1;i<=n;i++){
		if(!flag[i]){
			root=i;
		}
	}
	dfs(root,0);
	cout<<max(dp[root][1],dp[root][0]);
	return 0;
}
